INSERT INTO social_contents (`platform`, `main_material`, `keyword`, `content_id`, `content_url`, `title`, `content_text`, `author_name`, `author_id`, `upload_date`, `view_count`, `like_count`, `comment_count`, `comment_text`, `collected_at`) VALUES
    ('youtube', '나주배', '나주배', 'k1roNmHjoUA', 'https://www.youtube.com/watch?v=k1roNmHjoUA', '먹자!  나!주!시!곰!탕!', '가기 적절한 여행지 : https://www.naju.go.kr/tour/recommend/course/days2\n배 터지기 좋은 곳 : https://www.naju.go.kr/tour/food/restaurant\n\n출연: 배돌이, 배귀돌이, 홍돌이\n그림 : 메롱이\n더빙 : 백수묵시록\n\n#2026나주방문의해 #나주숏폼공모전', 'Merong', 'UCSkKzA2uLvEd3Y9Gfj_tq3g', '2026-04-27 10:18:25', 453652, 14431, 907, '["나주시 공무원한테 뺨이라도 맞으셨나요?", "나름 귀여운 마스코트였는데 겁나게 구수해졌네ㅋㅋㅋㅋ", "나주시에 비리가 있구나", "나주시한테 고소 받을거 같아서 싱글벙글한 메롱이는 개추 ㅋㅋㅋㅋㅋ", "아니 나주시는 왜 이런 감성을 좋아하는거야\\nㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ", "젓가락 한번 발리송마냥 ㅈㄴ 기깔나게 돌리네 ㅋㅋㅋㅋㅋㅋ", "숟가락으로 그릇치는게 ㅈㄴ 웃기네ㅋㅋㅋㅋㅋ", "이거 영업방해 아님? ㅋㅋㅋㅋㅋㅋ", "잘모르는거 알고 방심할 때 입에 쑤셔넣는 것도\\n지방 감성 제대로네ㅋㅋㅋㅋ", "이쯤되면 백수묵시록이나 메롱이 둘 중 하나는 나주시에 납치된 거 아니냐"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', '9QrZq0tJAbY', 'https://www.youtube.com/watch?v=9QrZq0tJAbY', '서양에서 안먹고 한국은 생으로 먹는 과일 클라스', '서양에서 안먹고 한국은 생으로 먹는 과일 클라스 #과일 #한국 #클라스 #배 #나주 배 #마이클잭슨', '트디남', 'UC0sIg38K_U-pS1LUqfT1FWA', '2025-03-10 04:00:07', 281618, 5750, 495, '["아니... 우리만 먹자...", "왜  비싼가  했더니   수출하고  있었네.....", "외국 생활할 때 제일 생각 난 것 두가지가 온돌이랑 배였음. 다른건 조금 부족하더라도 어떻게든 비슷한거 찾을수가 있는데, 그 두가지는 비슷하다고 하기에는 너무너무 멀어서", "아! 배가 요즘 수출 많이해서 비싸구나~~ ㅠㅠ", "배는 인정이지 😂😂 가끔 중국인들이 하는 야채가게에도 한국배 팜 있으면 무조건 사는데 다른 과일들보다 비싸긴해도 너무 맛있음 ㅎㅎ", "저 서양배도 안익었을 때 먹으면 좀 그렇지만, 잘익은 상태서 먹으면 정말 달아요. 과일을 빨리 익게 하려면 표면에 쇠주를 부어.", "배ㅡ호흡기를  도와줍니다..\\n통째로 삶아드시면 감기예방ㅡ더하기 도라지...더좋죠...😊😊", "미국 배들은 음식하거나 파이 만들때 빼고 다 그냥 먹음  익으면 엄청달고 입에 살살 녹음.  한국배는 한국 마트나 코스트코에 가면 살수있지만 중귝인들이 한문으로 도배된 상자에 영어로 아시안 배라고 해서 많은 마트에서 팔고 있음.", "외국인 친구가 술먹고 다음날 IdH 먹는다길래 미국 숙취음료인가 했는데 갈아만든 배였어서 진짜 빵터졌었던 기억이 있네요", "제발 소문 좀 내지 말자..."]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'ICf43FGbf1A', 'https://www.youtube.com/watch?v=ICf43FGbf1A', '[로창팝] 가자! 나주 배 축제!!(200만기념 뇌절2편)', '사랑하는 아내가 댓글 중, 이거 재밌겠다 추천해서 만들어봤습니다.\n200만 기념 뇌절이니 두개를 만들었어요!!\n\n\n무려 2개의 뽕짝을 만들었으니, 앞으로 몇달간은 락,메탈 강점기가 이어질 예정입니다\n\n\n\n#ai노래 #창팝 #로스트아크 #로아 #정상화 #신창섭 \n\n#sunoai 를 이용해 제작한 오리지널곡(의 커버곡)입니다.', '롹슨족', 'UCuAJmJmkyEFSJd0rAxcG7lQ', '2025-11-01 04:42:59', 104295, 1278, 470, '["살려는 드릴게~", "이런 가능성을 품고 있는 노래였는데\\n어쩌다 에버그레이스 몸통박치기가 곡을 먼저 가져가서 ㅋㅋㅋㅋㅋ", "롹슨족은 나주와 커넥션이 있는가? (모름)\\n나주 배는 왜 이렇게 맛있는가? (모름)\\r\\n다음 축제는 언제인가? (모름)\\n댄서는 누구인가? (모름)", "1.  축제기간 지남\\n2. 여름 끝나서 슬슬 추움\\n3. 원전은 그래도 로아엿는데 창섭이형 등판\\n4. 게임도 아님\\n5. 비꼬거나 비판같은 로창이 아니라 순수하게 정보와 홍보를 담고있음.\\n6. 광고도 아님\\n\\n이 광기는 대체.....", "선거철에 노래 왜트는지 알겠다.\\n귀에 속속들어오잖아", "정보) 마이클잭슨도 생전 내한때 나주배먹어보고 극찬하면서 수십 박스를 사갔다", "노래가 아주 건전하다 보니 요 며칠간 일하면서 원본보다도 점점 많이 흥얼거리게 됨 ㅋㅋㅋㅋㅋ", "곡이 제자리를 찾았나 싶었는데 여기서도 돌려지는 창섭햄ㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋㅋ", "그래 이거 축제 홍보용으로 딱이라니까 ㅋㅋㅋㅋ", "원곡에서 화가 담긴채 하나하나 비판하던 곡이 나주배축제로 바꾸니까 순한맛으로 바뀐데다가 나주에 이런게 있었구나 새로운 정보를 알게되었음 ㅋㅋㅋㅋㅋㅋㅋㅋ 시 자체에서 유튜브 홍보 열심히 할려던 이유 알거 같음 내년에 한번 갈까? 라는 생각이 막 드네"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'jmJM0g6KWWg', 'https://www.youtube.com/watch?v=jmJM0g6KWWg', '"나주 배가 최고예요" 숙취 해소 음료로 100% 나주 배 과즙 마신다는 호주 근황 / 스브스뉴스', '호주에 한국산 나주 배즙이 숙취해소제로 인기를 끌고 있습니다. \n한국에서 나주 배의 참맛을 느낀 호주 청년들이 만든 BAE JUICE 브랜드인데요.\n호주 울월스 마트에도 입점했다고 해요. \n \n어쩌다 나주 배즙을 호주에 수출하게 됐는지 직접 물어봤습니다. \n자세한 내용은 영상에서 확인하세요! \n\n✔ 뉴스에는 위아래가 없다, 스브스뉴스\n\n\n- 비즈니스 문의 -\n브랜디드 콘텐츠 기획/제작 문의: branded@sbs.co.kr\n기업/브랜드 채널 컨설팅 및 기획/제작 문의: solution@sbs.co.kr\n\n- 링크 -\n175 플래닛 : https://175planet.com/\nInstagram :  https://www.instagram.com/subusunews\nFacebook :  https://www.facebook.com/subusunews\n홈페이지 : https://news.sbs.co.kr/news/subusuNews.do?plink=GNB&cooper=SBSNEWS', '스브스뉴스 SUBUSUNEWS', 'UCQabORQKQRHP-iUqe-xIFvg', '2023-08-31 09:00:26', 58928, 1092, 138, '["00:40 한국 배에 푹 빠진 호주 청년", "배를 일부러 BAE라고 남겨놓은거 같음. 한글의 배와 발음이 같으면서도 영어로 BAE는 자기 같이 친근하게 연인을 부를때 Baby의 뜻으로도 쓰여서 영어로만 봤을때는 귀여운 이름임", "전 여친과 사업 중이라고? ㄷㄷ", "예전에 해외에서 갉아만든 배 음료의 배를 ldH 로 부르며 찾아다닐정도로 큰 인기를 끌었다고 하더라고요.   그냥 아, 맛있다 하고 끝날 수 있었는 데 그걸 상품화 시킨 대표님 센스..d 맛있고, 건강하면서 숙취해소에도 좋다는 점에서 히트할 만 한거 같아요.", "외국애들 사업참잘해\\n토끼소주도 그렇고 공무원에매달려있던나라랑 달라 달라", "배도라지가 환절기에 얼마나 좋은지 알려주고 싶다.", "와...  오픈마인드  전여자친구랑 동업 와... 역시 글로벌  혁명적이네...", "우와 이게 현지에서 먹히는구나... 사업은 이렇게 하는건가?", "응원합니다~^^", "배주스 공동창업자분 애국자 ㅎㅎㅎ ❤❤❤❤❤❤❤❤❤ 존경합니다 ㅎㅎㅎ ❤❤❤❤❤ 배주스 화이팅하세요 ㅎㅎㅎ ❤❤❤❤❤❤❤"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'LkIqfXV655Q', 'https://www.youtube.com/watch?v=LkIqfXV655Q', '나주의 명물, 명품 나주배 [광주MBC 다큐프라임]', '나주의 명품 브랜드 나주배\n#나주배 #나주 #로컬브랜드', '광주MBC', 'UCRvrYUbatHPDc-snY-jCG0A', '2019-04-12 04:30:00', 6139, 54, 6, '["나주배좀.먹어.보자고요", "나주배가 👍 다 나주는 배의\\n명산지다", "수출용은 포장상자가 다른가요?\\n해외에서 나주배가 언젠가서부터 당도가 많이 부족하고\\n 맛이 원래나주배맛이 아니어서요…\\n이젠 선뜻 구매하기가 망설여집니다..", "실제 방영 일자가 궁금합니다. 꽤 오래 전인것 같은데, 언제쯤 일까요?", "원앙  황금 신화  만수   이런배들은성장촉진제를  제일많이발라서 추석전에나온배들이다"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', '1LGhNlglI3o', 'https://www.youtube.com/watch?v=1LGhNlglI3o', '나주 배, 엇갈린 운명? 전통과 실용 사이에서 길 찾기', '저희는 나주 배 생산지에서 시장 변화와 전통적인 고급 과일 이미지 사이의 균형을 찾는 여정을 탐구합니다. 신고 품종의 수확 시기, 조생종 도입 노력, 그리고 연중 공급 체계 구축을 위한 시도를 통해 나주 배의 미래를 조명합니다. #나주배 #배농사 #과일 #농업 #추석 #신고배 #조생종 #농산물 #한국농업 #푸드', '맛가득', 'UCEopmcJVoSnsrt3RvxFvJHQ', '2025-07-06 18:07:12', 3725, 9, 2, '["배농사가짱"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'PjBdDAhupNc', 'https://www.youtube.com/watch?v=PjBdDAhupNc', '나주배 선물세트 2만원대 가성비 선물 합격! #나주배선물세트 #돌쇠네농산물', '👇👇구매방법 👇👇\n✔ https://www.dolfarmer.com/Goods/Detail/SSM65372201?ch=90895\n✔ 커뮤니티에서 바로가기 링크 통해 구매\n✔ 문자주문 010-2463-7396', '돌쇠네농산물', 'UC8GdMTYv6X3CTsXXwKmwLww', '2025-09-18 07:32:12', 3065, 22, 12, '["👇👇구매방법 👇👇\\r\\n✔ 영상 설명란 더보기에서 확인\\r\\n✔ 커뮤니티에서 바로가기 링크 통해 구매\\r\\n✔ 문자주문 010-2463-7396", "감사합니다 풍년이네요. 부자되세요", "배 좋아요 🎉", "배", "배", "배", "배"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'nr4rioefpeo', 'https://www.youtube.com/watch?v=nr4rioefpeo', '"수정 시기에 벼락 우박"‥ 나주 배 농가 직격탄 (2026.04.07/뉴스데스크/광주MBC)', '지역사 채널의 동영상 링크 (https://www.youtube.com/watch?app=desktop&v=_uxsZ8CsvuI) \n\n#광주MBC #우박 #피해 #나주배\n#MBC #뉴스 #뉴스데스크 #MBC뉴스 #뉴스투데이\nㅤ\nⓒ MBC & iMBC 무단 전재, 재배포 및 이용(AI학습 포함)금지', 'MBCNEWS', 'UCF4Wxdo3inmxP-Y59wXDsFw', '2026-04-08 08:30:26', 1613, 19, 1, '["농작물자연재난보험 이라도꼭가입해주셨으면좋겠습니다\\n정부에서는 우박냉해\\n피해입은지역을살펴\\n주시기를진심으로\\n바랍니다"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'rc3QYJzUD5o', 'https://www.youtube.com/watch?v=rc3QYJzUD5o', '[찾아가는K] “색보다 맛에 집중”…나주배 명성 되찾는 도전 / KBS  2025.09.18.', '[앵커]\n\n 명절 선물과 차례상에 빠질 수 없는 과일, 바로 배입니다.\n\n 그 중에서도  ''나주배''는  배 하면 바로 떠올릴 만큼 명성이 높았는데요.\n\n 최근엔  비싼 가격과 당도 하락 등으로 예전만큼의 인기를  얻지 못하고 있습니다.\n\n 이에  나주배를 되살리기 위한 시도가 이어지고 있는데요.\n\n 색은 덜 노랗지만 맛이 더 좋은 배를 만드는 농민들, 찾아가는K 김대영 뉴스캐스터가 만나봤습니다.\n\n [리포트]\n\n 영암에서 생산된 배를 포장만 ''나주배''로 바꾸는 이른바 ''박스 갈이''.\n\n 나주배의 인기가 워낙 높아 벌어진 일입니다.\n\n 배 하면 ''나주배''를 떠올리던 시절, 이제는 옛말이 돼 가고 있습니다.\n\n 소비자뿐 아니라 도매시장 중매인들부터  나주배 인기가 떨어진 걸 느낍니다.\n\n 최근엔 나주배보다 다른 지역의 배가  더 잘 팔릴 정돕니다.\n\n [고길석/한국청과 본부장·가락시장 경매사 : "가락시장 전체를 봐서는 나주배는 그렇게 인기가 별로 없습니다. 지금 인기 있는 곳들은 충청도, 경기도 이쪽 배들이 상당히 인기가 좋거든요."]\n\n 나주배의 위기를 극복하기 위한 시도가 이어지는 이윱니다.\n\n올해 본격적인 수확을 앞두고 있는 나주의 한 배 농장입니다.\n\n먹음직스러운 배가 주렁주렁 달려 있는데요.\n\n수확한 배의 표면을 보면, 색깔은 청색을 띄고 있죠.\n\n보통 황금색을 띄던 나주배의 색깔이 왜 갑자기 달라졌을까요?\n\n그 이유를 알아보겠습니다.\n\n 나주에서 20년 넘게 배를 키우는 김준 씨.\n\n 2년 전부터 농민 13명과 함께 ''작목반''을 꾸렸습니다.\n\n 나주배 당도가 예전만 못하고 식감도 떨어진다는  소비자들의 목소리가 계기가 됐습니다.\n\n [김준/신고청배 작목반 회장 : "추석 출하를 안 하더라도 소비자한테 정말 맛있는 배, 소비자가 원하는 배, 그 배를 저희가 생산해서 유통을 하고 싶어서..."]\n\n 작목반은 배를 키울 때 씌우는 ''봉지''에 착안했습니다.\n\n 배꽃이 피고 난 뒤 한두 달 사이에 씌우는 봉지는 병해충을 막아 주는 역할을 합니다.\n\n 배 색깔이 더 선명하게 나오도록 봉지를 두세 겹씩 씌우는 게 보통입니다.\n\n 하지만, 이러면 햇볕을 덜 받아 당도가 떨어질 수 있습니다.\n\n 작목반 농민들은 봉지를 덜 써보기로 했습니다.\n\n 색보다 맛에 중점을 두자는 뜻입니다.\n\n 이렇게 수확된 배의 이름은 ''신고청배''로 정했습니다.\n\n신고청배는 기존 가장 보편적인 품종인 ''신고배''와 품종은 동일합니다. \n\n하지만 당도를 높이기 위해 배에 봉지를 하나만 씌웠다는 차이가 있습니다.\n\n[김준/신고청배 작목반 회장 : "''일중 봉지''입니다. 이걸 씌우게 되면 햇빛 투과량이 굉장히 좋아요. 그래서 배도 잘 크고 당도도 잘 올라옵니다. 근데 색깔이 좀 안 좋죠. 그래서 이 색깔은 저희가 포기하고 맛으로 승부를 하겠다는 취지에서 ‘신고청배’라고 이름을 지었습니다."]\n\n 작목반이 금기시한 건  성장 촉진제 사용.\n\n 과일 크기는 빠르게 키우지만 맛을 떨어뜨리는 원인으로 봤기 때문입니다.\n\n 실제로 기존 배와 새로 수확한 신고청배의  당도를 비교해 봤더니,  신고청배의 당도가 13브릭스로 기존 배보다 1~2브릭스 정도  높게 측정됐습니다.\n\n [고길석/한국청과 본부장·가락시장 경매사 : "과일의 당도를 1브릭스 이상 올리는 건 굉장히 어렵습니다. 예를 들어 한 달 내내 비가 오지 않고 날씨가 좋아도 당도 1브릭스 올리기가 상당히 힘듭니다."]\n\n 봉지를 덜 쓰고  촉진제도 안 맞히다 보니 원가 절감 효과까지 얻었습니다.\n\n 작목반은 이에 아예 봉지를 씌우지 않는 재배법도 시험 중입니다.\n\n 과일이 너무 달아지면서 까치 등 조류가 쪼아 먹는 일이 잦아진다는 점은 해결 과젭니다.\n\n 올해 예상 생산량은 5백 톤. \n\n시장 반응은 미지수지만 작목반은 기대가 큽니다.\n\n [허영/신고청배 작목반 회원 : "(조류 피해 때문에 생산량이) 20~30%는 줄지 않을까, 그 아삭거림이라든가, 그런 것들이 살아 있기 때문에 호응도는 좋을 것으로 저는 예상하고 있습니다."]\n\n 당도에 따라 자동으로 배를 선별해 유통되는 나주배의 품질을 높이는 나주시 농산물 유통센터와, 나주시장이 직접  품질을 인증하는 제도 등, 나주배의 영광을 찾으려는 노력은 이어지고 있습니다.\n\n[한광범/나주시 배과수팀장 : "그동안에 저희들은 지베렐린(성장 촉진제) 때문에 소비자들의 신뢰가 약간 무너진 상태인데 그걸 극복하기 위해서 나주시에서는 ''무GA(성장 촉진제 미사용)'' 사업을 펼치고 있습니다. 그래서 현재 저희가 1800㏊ 중에서 600㏊ 정도는 ''무GA''로 생산되고 있습니다. 향후에도 지속적으로 확대해 나갈 계획입니다."]\n\n음식과 과일에 대한 소비자들의 수요가 빠르게 바뀌고 있는 요즘, 현실에 안주하지 않고 신속하게 변화에 대처하는 지역 농가들도 늘고 있습니다.\n\n나주배 당도를 높이려는 ''신고청배'' 재배 시도 역시 마찬가집니다.\n\n''신고청배''가 나주배의 명성을 되찾을지 주목됩니다.\n\n찾아가는 K였습니다.\n\nCopyright ⓒ KBS. All rights reserved. 무단 전재, 재배포 및 이용(AI 학습 포함) 금지', 'KBS NEWS 광주전남', 'UCLqL_rpuTp1bIe5YuHjbufA', '2025-09-18 10:36:15', 1366, 11, 1, '["나주배도유명하겠지만요ᆢ세종나리마을배도\\n유명하거든요ᆢ아삭아삭한시원하고\\n감기천식에좋은햇배\\n맛보러오세요ᆢ\\n도담동로컬매장에도\\n납품을하고있답니다"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'o5hKRq10L1s', 'https://www.youtube.com/watch?v=o5hKRq10L1s', '시원달콤 나주배! 최저가 할인!🍐', '단단하고 튼실한 신고배 3kg 7천원대!\n할인 딱 4일 남았습니다!\n\n7~9과 정도 들어있어요~\n\n✅ 배의 고향, 나주에서 재배!\n✅ 고당도! 과즙이 가득\n✅ 물렁물렁X 과육이 단단하고 아삭!\n\n이 가격 마트, 시장 어디에서도 볼수 없습니다!', '농가살리기', 'UC-hzcfimUXqHkCXSuNnWIjQ', '2025-09-26 02:51:34', 981, 4, 0, '[]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'XFLf_v_Ako0', 'https://www.youtube.com/watch?v=XFLf_v_Ako0', '까맣게 타버린 배꽃.. 나주 배 농가 "농업재해로 인정해달라" (뉴스데스크 2026.4.29 광주MBC)', '(앵커)\n배 주산지인 나주에서 \n때아닌 우박과 냉해로 배꽃이 까맣게 \n타 죽는 피해가 속출하고 있습니다.\n\n농민들은 농업재해로 인정하고 \n정부 차원의 근본적인 대책을 \n마련해달라고 촉구했습니다.\n\n보도에 김영창 기자입니다.\n\n(기자) \n과수원에 메말라 죽은 배꽃들이 \n널브러져 있습니다.\n\n지난 4월 초, 나주 일대에 \n우박이 내린 시점부터 기온이 영하 3도로 \n떨어지면서 얼어 죽은 겁니다.\n\n이때문에 착과율 저하로 이어지면서\n배 열매는 찾아볼 수 없을 정도입니다.\n\n* 조기원 / 배 농가\n"3월달부터 기온이 많이 높아서 배꽃들이 일찍 폈어요. 인공수분할 시기에 서리 피해로 인해서 꽃들이 다 죽어가지고 착과가 안된 상황입니다."\n\n이렇게 저온 피해를 입은 곳은\n나주 전체 배 재배면적 1천 600여ha 중,\n1천여 ha로 잠정 파악됐습니다.\n\n그러나 이렇다 할 피해 지원이 없는 상황.\n\n농민들은 결국 나주시청을 찾아\n저온 피해 대책을 마련해 줄 것을 \n촉구했습니다.\n\n"배 착과불량 피해조사를 즉각 실시하라.\n실시하라. 실시하라."\n\n조속히 현장조사를 통해 \n정확한 피해 규모를 확인하고, \n이를 농업재해로 인정해달라는 겁니다.\n\n농업재해로 인정될 경우,\n복구비를 지원받을 수 있습니다.\n\n농민들은 또 "기후변화로 인해 전국의 과수원에서 착과 불량이 매년 나타나고 있다"며 \n"이제는 지방이 아닌 중앙정부 차원에서 \n나서야 한다"고 강조했습니다.\n\n* 김병식 / 사단법인 배상산자협회장\n"(기후변화 피해) 이거는 농민들이 어떻게 할 수 없는 재해거든요. 이거는 나라에서 해결을 해줘야 하는게 맞다고 봅니다."\n\n농민들의 요구에 \n나주시와 전남도는 대응책을 내놨습니다.\n\n저온 피해가 농업 재해로 \n공식 인정될 수 있도록 농림부에 실질적인 \n지원 방안을 건의하겠다는 방침입니다.\n\n또 지속적인 현장조사와 피해 규모를 파악해\n기후변화에 따른 농가 피해 대책도 \n마련할 계획이라고 밝혔습니다.\n\nMBC뉴스 김영창입니다.\n\n\n\n#농업재해 #저온피해 #기후변화 #농가피해', '광주MBC뉴스', 'UCr0LBUePUC5XnejgV4JmboA', '2026-04-29 13:14:44', 827, 5, 7, '["다시금 배과수 농가들께서 일어설 수 있도록 정부에서 조속한 농업 재해 인정과 함께 정부차원의 대책 마련을 기대해봅니다.", "헉 갈배 음료도 가격 올라가겠네", "보험  넣어야 합니다", "해마다 반복돼는 재해인정 논란...", "잘될때는 싸게파나?"]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'LLV_oM64Pb4', 'https://www.youtube.com/watch?v=LLV_oM64Pb4', '“생장촉진제 안 써요”…나주 배, 옛 명성 찾기', '앵커 멘트\n\n 간혹 배를 먹다가 푸석거려 맛이 없다고 느낀 경험 있으실 겁니다.\n\n 배를 빨리 수확하려고 생장 촉진제를 써 나타나는 현상인데  국내 최대 배 주산지인 전남 나주에서 이 촉진제 사용 줄이기에 나섰습니다.\n\n 윤주성 기자입니다.\n\n 리포트\n\n 전남 나주의 배 과수원입니다.\n\n 예년 같으면 배의 생장을 돕는 촉진제를 열매 줄기에 바를 시기지만  올해는 거의 사용하지 않습니다.\n\n 배 크기가 작거나 수확이 다소 늦어도 전과 달리 농협에 전량 출하할 수 있기 때문입니다.\n\n 농협은 이처럼 생장 촉진제를 사용하지 않는 농가와 주로 계약 재배해 촉진제 사용을 억제하고 있습니다.\n\n 인터뷰 나종렬(마한농협 판매팀장) : "조금 적어도 고품질로 생산하자는 취지로 아무래도 지베렐린 보다는 무지베렐린, 촉진제를 덜 쓰는 분위기로 많이 바뀌었죠."\n\n 생장 촉진제를 쓰면 수확시기를 일주일가량 앞당길 수 있지만, 과육이 물러지는 등 품질이 떨어질 수 있기 때문입니다.\n\n 지방자치단체도 생장 촉진제를 쓰지 않는 농가에 포장비 등을 일부 지원합니다.\n\n 인터뷰 김상준(배 재배 농민) : "박스당 50% 정도... 한 박스가 천5백 원 정도 하면 거기서 50% 정도 보조해주고  있습니다."\n\n 지난 2015년부터 촉진제 사용 억제를 위한 정책을 적극 펼치고 있습니다.\n\n 나주시는 생장 촉진제 사용 여부를 배 포장지 등에 표시하는 방안도 적극 검토할 계획입니다.\n\n KBS 뉴스 윤주성입니다.', 'KBS News', 'UCcQTRi69dsVYHN3exePtZ1A', '2017-05-29 00:00:02', 749, 1, 0, '[]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'Z2TryC4-VzU', 'https://www.youtube.com/watch?v=Z2TryC4-VzU', '나주하면은 나주배 햇배가 나왔어요  팔아주세요 주문받습니다 #친환경 #저농약 #GAP심온농장 ', '나주배 주문받아요 1년 12달 팔아요\n친환경 저농약 GAP인증', '승씨농장장', 'UCj8o7_SKzK9DcFho8VPD63A', '2025-08-25 16:01:02', 729, 16, 0, '[]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'cjPPXWx4jmw', 'https://www.youtube.com/watch?v=cjPPXWx4jmw', '나주배 15kg 1박스가 만원??!! 요건 확실히 미친거 맞음!!!', NULL, '과일에 미친 과일사장', 'UC92TD0Fp06CQYXwRti7RQSQ', '2024-11-01 02:39:58', 630, 4, 0, '[]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', '-wMQSTbMcdA', 'https://www.youtube.com/watch?v=-wMQSTbMcdA', '♥️맛있겠주♥️먹고싶주♥️ 상큼 아삭 시원한 나주배 | 나주시', '#kbc #광주방송 #kbc광주방송 #도시락 #꿀잼남도 #남도여행 #가을 #가을여행\n#나주 #나주배 #배 효능 #식이섬유 #비타민 #기관지보호 #소화개선 #숙취완화\n#한라봉 #나주 한라봉 #나주 특산물 #지역브랜드 #천년이음 #남자 배 #여자 배 \n#나주 디저트 카페 #나주 배 디저트 카페 #나주 배 양갱 #나주 배 빵\n#김담희', 'KBC 콘텐츠', 'UC-wL5ml0t2M_947DLIHdDjg', '2025-11-21 11:02:08', 579, 4, 0, '[]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'hrmqaWulP08', 'https://www.youtube.com/watch?v=hrmqaWulP08', '🍐나주배 오픈특가 5키로 16,900원!!', '🍐나주배 5키로 16,900원!!\n\n과일에 깐깐한 엄마도 \n"여기 신선하고 맛 좋다"며 \n한 박스 더 주문해달라 하셨어요.\n\n아삭하면서도 부드럽고, 과즙이 정말 시원해서 \n배 안좋아하는 저도 순식간에 다 먹어버렸답니다.\n\n✅ 첫 수확 햇배의 신선함\n✅ 5kg 16,900원 초특가\n\n놓치면 1년 기다려야 하는 맛, 지금 바로 만나보세요!\n\n#나주배 #제철과일 #과일맛집 #가을과일', '시골청년', 'UCCb1Qm-XlDpErzKQXVusDAA', '2025-09-08 06:48:56', 517, 0, 0, '[]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'mgLt6bQmHzc', 'https://www.youtube.com/watch?v=mgLt6bQmHzc', '"수정 시기에 벼락 우박".. 나주 배 농가 직격탄 (뉴스투데이 2026.04.08 광주MBC)', '(앵커)\n어제(6) 한낮에 갑자기 쏟아진 \n굵은 우박에 놀란 분들 많으실 겁니다.\n\n전남 곳곳에서는 농작물 피해가 속출했는데요.\n\n특히 배꽃이 한창 피어난 \n나주 배 농가는 직격탄을 맞았습니다.\n\n주지은 기자가 현장에 한걸음 들어가 취재했습니다.\n\n(기자)\n어제(6) 오후 2시쯤 \n광주와 전남 일대에 동전만한 우박이\n사정없이 쏟아졌습니다.\n\n"난리났네 우박이. 우박이 난리났어."\n\n하늘에서 쏟아진 우박 폭탄에\n배나무들이 속절없이 매를 맞았습니다.\n\n우박에 맞은 배꽃들이 \n바닥에 힘없이 떨어져 있습니다.\n\n평년보다 일찍 개화한 상태에서 \n무방비로 우박과 강풍을 \n정면으로 맞은 탓입니다.\n\n당장 올해 결실을 맺어야 할 꽃눈이 \n통째로 떨어져 나가면서, \n내년 농사에도 지장이 생겼습니다.\n\n* 김종일 / 배 과수원 운영\n"지금 이 시기가 배꽃이 떨어질 시기가 아니거든요. 지금 떨어진 배꽃이 한창 수정해야 할 시기에요. 올해도 올해지만 내년에도 문제가 돼요."\n\n설상가상으로 아침 최저기온이 \n급격히 떨어질 것으로 예상되면서\n상처 입은 꽃들에 \n추가 냉해 피해까지 우려되는 상황입니다.\n\n"배꽃 수정 시기는 배의 수확량과 품질을 \n결정짓는 가장 중요한 시기인데요.\n\n우박으로 낙화 피해를 입으면서\n배 농가에 갑작스러운 악재가 닥쳤습니다."\n\n지자체에서도 긴급 현장 점검에 나섰습니다.\n\n* 유덕규 / 전남도 농축산식품국장\n"우박에 따른 피해를 행정에서는 지금 조사하고 있고... 현재 상황에서는 피해율보다 적과같은 것이 필요한 부분이 있어서...상황을 좀 더 지켜보고 지원 대책들이 나올 수 있도록 강구하겠습니다."\n\n나주를 비롯해 우박이 덮친 \n전남 6개 시군의 피해 면적은 \n800ha 이상으로 집계됐습니다.\n\n이 중 나주 배 농가의 낙화 피해가 \n730ha로 대부분을 차지했고, \n양파 잎 손상이나 축사 파손 등의 피해도 잇따랐습니다.\n\n한편 기상청은 이번 우박이 \n상·하층의 극심한 기온 차로 발생했고, \n4월 우박은 지난 2022년 이후 \n4년 만이라고 밝혔습니다.\n\nMBC뉴스 주지은입니다.\n\n\n\n#우박 #피해 #나주배', '광주MBC뉴스', 'UCr0LBUePUC5XnejgV4JmboA', '2026-04-07 23:45:20', 512, 0, 0, '[]', '2026-05-21 14:39:14'),
    ('youtube', '나주배', '나주배', 'mn0t7g6kvwU', 'https://www.youtube.com/watch?v=mn0t7g6kvwU', '나주배 선물세트 5kg 7.5kg 15kg (자매품 가정용 못난이 5kg)', '♥구입처♥\nhttps://smartstore.naver.com/sunnynury/products/9176389598\n명절 과일 선물세트의 대명사, 나주배 선물세트입니다.\n\n올해 수확하는 싱싱한 나주배 햇배이며, 품종은 신고배입니다.\n\n신고배는 1930년대에 일본에서 개량되었으며, 과실의 크기가 크고 무게는 500g 이상 나가는 품종입니다.\n과육이 부드럽고 과즙이 풍부하며 신 맛이 적고 당도가 높아 인기가 높은 신고배는 양력 9월 중하순~10월 중순이 수확기이고, 상온에서 90일 가량 보관이 가능합니다.\n(기후 변화로 인해 수확기가 점점 앞당겨지는 추세입니다.)\n\n나주배 특품 선물세트 구성\n5kg(5~7과) / 5kg(8~10과)\n7.7kg(7~10과) / 7.5kg(11~13과)\n15kg(16~20과) / 15kg(21~25과)\n\n가정용 흠집과 구성\n5kg(5~7과) / 5kg(8~10과)\n\n싱싱한 나주배를 꼼꼼하게 이중 선별한 후 완충 겹포장하여 전라남도 나주 산지에서 직접 발송합니다.', 'Sunnynury', 'UCGQiqcMujHg6uXiACWXIcnA', '2024-08-31 12:52:43', 408, 3, 4, '["가정용 10킬로 얼마인가요\\n선물요은얼마인가요\\n전화 번호도올려주세요", "가격이 없는것은 믿을수가 없지요.\\n배는 여기도 많지요.!"]', '2026-05-21 14:39:14'),
